import React from 'react'
import { useSelector, useDispatch } from 'react-redux'
import { formatPrice } from '../../utils/helpers'
import { removeItem, updateItemQuantity, clearItems } from '../../redux/cartSlice'
import { useNavigate } from 'react-router-dom'

export default function Cart() {
  const items = useSelector((state) => state.cart.items)
  const dispatch = useDispatch()
  const navigate = useNavigate()
  const subTotal = items.reduce((sum, item) => sum + (item.lineTotal || 0), 0)

  if (!items.length) {
    return (
      <div className="p-6 min-h-[60vh]">
        <div className="mx-auto max-w-2xl rounded-[2rem] border border-dashed border-slate-300 bg-slate-50 p-10 text-center shadow-sm">
          <p className="text-sm uppercase tracking-[0.2em] text-slate-500">Cart is empty</p>
          <h2 className="mt-4 text-3xl font-semibold text-slate-900">Nothing to checkout yet</h2>
          <p className="mt-3 text-slate-600">Browse the menu and add your favorite pizzas to start ordering.</p>
          <button
            type="button"
            onClick={() => navigate('/dashboard')}
            className="mt-8 rounded-full bg-primary-600 px-6 py-3 text-sm font-semibold text-white transition hover:bg-primary-700"
          >
            Continue shopping
          </button>
        </div>
      </div>
    )
  }

  return (
    <div className="p-6 max-w-6xl mx-auto">
      <h2 className="text-3xl font-semibold text-slate-900 mb-6">Your Cart</h2>

      <div className="grid gap-8 lg:grid-cols-[1.5fr_0.8fr]">
        <div className="space-y-5">
          {items.map((item) => (
            <div
              key={item._key}
              className="rounded-[1.75rem] border border-slate-200 bg-white p-5 shadow-sm"
            >
              <div className="flex flex-col gap-4 lg:flex-row lg:items-center lg:justify-between">
                <div>
                  <p className="text-lg font-semibold text-slate-900">{item.name}</p>
                  <p className="mt-1 text-sm text-slate-600">{item.size}</p>
                  {item.toppings?.length > 0 && (
                    <p className="mt-2 text-sm text-slate-500">
                      Toppings: {item.toppings.map((t) => t.name).join(', ')}
                    </p>
                  )}
                </div>

                <div className="flex flex-col gap-4 sm:items-end">
                  <div className="flex items-center gap-2 rounded-full border border-slate-200 bg-slate-50 px-3 py-2">
                    <button
                      type="button"
                      onClick={() => dispatch(updateItemQuantity({ key: item._key, quantity: item.quantity - 1 }))}
                      disabled={item.quantity <= 1}
                      className="rounded-full bg-white px-3 py-1 text-lg font-semibold text-slate-700 hover:bg-slate-100 disabled:cursor-not-allowed disabled:opacity-50"
                    >
                      −
                    </button>
                    <span className="min-w-[2rem] text-center text-base font-semibold">{item.quantity}</span>
                    <button
                      type="button"
                      onClick={() => dispatch(updateItemQuantity({ key: item._key, quantity: item.quantity + 1 }))}
                      className="rounded-full bg-white px-3 py-1 text-lg font-semibold text-slate-700 hover:bg-slate-100"
                    >
                      +
                    </button>
                  </div>
                  <p className="text-lg font-semibold text-slate-900">{formatPrice(item.lineTotal)}</p>
                  <button
                    type="button"
                    onClick={() => dispatch(removeItem(item._key))}
                    className="text-sm font-semibold text-rose-600 hover:text-rose-700"
                  >
                    Remove item
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>

        <aside className="rounded-[2rem] border border-slate-200 bg-white p-6 shadow-sm">
          <div className="space-y-5">
            <div>
              <p className="text-sm uppercase tracking-[0.18em] text-slate-500">Order summary</p>
              <p className="mt-2 text-2xl font-semibold text-slate-900">Ready to checkout</p>
            </div>

            <div className="space-y-3 rounded-3xl bg-slate-50 p-4">
              <div className="flex items-center justify-between text-sm text-slate-600">
                <span>Items</span>
                <span>{items.length}</span>
              </div>
              <div className="flex items-center justify-between text-sm text-slate-600">
                <span>Subtotal</span>
                <span>{formatPrice(subTotal)}</span>
              </div>
            </div>

            <button
              type="button"
              onClick={() => navigate('/checkout')}
              className="w-full rounded-full bg-primary-600 px-5 py-3 text-sm font-semibold text-white transition hover:bg-primary-700"
            >
              Continue to checkout
            </button>

            <button
              type="button"
              onClick={() => dispatch(clearItems())}
              className="w-full rounded-full border border-slate-200 bg-white px-5 py-3 text-sm font-semibold text-slate-700 hover:bg-slate-50"
            >
              Clear cart
            </button>
          </div>
        </aside>
      </div>
    </div>
  )
}
